net per_key_suppression "Pass the first request with no same-key suppression"

(requests) -request-> [admit] -request-> (admitted)
@arc_2: (suppressions) -suppression->0 [admit]

[admit] handler "admit_request"

@arc_2 correlate cel "token.key == binding.requests[0].key"

marking initial (requests) <- $token_0
marking initial (requests) <- $token_1
marking initial (suppressions) <- $token_2
$token_0: request {"key":"A"}
$token_1: request {"key":"B"}
$token_2: suppression {"key":"A"}
